const newFiles:Record<string,string>={"client/src/interpolation.ts": "export type PositionSnapshot={x:number;y:number;angle:number;receivedAt:number};\nexport type VisibilityResult={visibleInWorld:boolean;visibleOnMinimap:boolean;revealedByShot:boolean;revealedByHit:boolean};\n\nexport function pushPositionSnapshot(buffer:PositionSnapshot[],snapshot:PositionSnapshot,max=8){\n  const last=buffer.at(-1);\n  if(last&&last.receivedAt===snapshot.receivedAt)return buffer;\n  buffer.push(snapshot);\n  while(buffer.length>max)buffer.shift();\n  return buffer;\n}\n\nexport function samplePosition(buffer:readonly PositionSnapshot[],targetTime:number){\n  if(!buffer.length)return undefined;\n  if(buffer.length===1||targetTime<=buffer[0]!.receivedAt)return {...buffer[0]!};\n  for(let i=1;i<buffer.length;i++){\n    const b=buffer[i]!;\n    if(targetTime>b.receivedAt)continue;\n    const a=buffer[i-1]!;\n    const span=Math.max(1,b.receivedAt-a.receivedAt);\n    const t=Math.max(0,Math.min(1,(targetTime-a.receivedAt)/span));\n    const angleDelta=Math.atan2(Math.sin(b.angle-a.angle),Math.cos(b.angle-a.angle));\n    return {x:a.x+(b.x-a.x)*t,y:a.y+(b.y-a.y)*t,angle:a.angle+angleDelta*t,receivedAt:targetTime};\n  }\n  return {...buffer.at(-1)!};\n}\n\nexport function zoneDirection(dx:number,dy:number){\n  if(Math.hypot(dx,dy)<12)return '현재 위치';\n  const names=['동','남동','남','남서','서','북서','북','북동'];\n  const normalized=(Math.atan2(dy,dx)+Math.PI*2)%(Math.PI*2);\n  return names[Math.round(normalized/(Math.PI/4))%8]!;\n}\n", "server/tests/interpolation.test.ts": "import { describe, expect, it } from 'vitest';\nimport { pushPositionSnapshot, samplePosition, zoneDirection } from '../../client/src/interpolation.js';\n\ndescribe('Refactor 005 interpolation helpers', () => {\n  it('keeps hidden player snapshots flowing and samples the current interpolated location', () => {\n    const buffer: Array<{ x:number; y:number; angle:number; receivedAt:number }> = [];\n    pushPositionSnapshot(buffer, { x: 10, y: 20, angle: 0, receivedAt: 100 });\n    pushPositionSnapshot(buffer, { x: 110, y: 20, angle: Math.PI / 2, receivedAt: 200 });\n    const sampled = samplePosition(buffer, 150)!;\n    expect(sampled.x).toBeCloseTo(60);\n    expect(sampled.y).toBeCloseTo(20);\n    expect(sampled.angle).toBeCloseTo(Math.PI / 4);\n  });\n\n  it('caps interpolation history and labels zone movement directions', () => {\n    const buffer: Array<{ x:number; y:number; angle:number; receivedAt:number }> = [];\n    for (let i = 0; i < 20; i += 1) pushPositionSnapshot(buffer, { x: i, y: 0, angle: 0, receivedAt: i }, 8);\n    expect(buffer).toHaveLength(8);\n    expect(zoneDirection(100, -100)).toBe('북동');\n  });\n});\n"};

function findBlock(lines:string[],block:string[],near:number){
  if(block.length===0)return Math.max(0,Math.min(lines.length,near));
  const matches:number[]=[];
  outer:for(let i=0;i<=lines.length-block.length;i++){
    for(let j=0;j<block.length;j++)if(lines[i+j]!==block[j])continue outer;
    matches.push(i);
  }
  if(!matches.length)return -1;
  return matches.reduce((best,value)=>Math.abs(value-near)<Math.abs(best-near)?value:best,matches[0]!);
}

function applyUnified(relative:string,diff:string){
  const target=path.join(root,relative);
  if(!fs.existsSync(target))throw new Error(`필수 파일 없음: ${relative}`);
  const raw=fs.readFileSync(target,'utf8');
  const hadFinalNewline=raw.endsWith('\n');
  let lines=raw.replace(/\r\n/g,'\n').split('\n');
  if(lines.at(-1)==='')lines.pop();
  const diffLines=diff.replace(/\r\n/g,'\n').split('\n');
  let index=0;
  let offset=0;
  while(index<diffLines.length){
    const header=diffLines[index];
    if(!header?.startsWith('@@')){index++;continue;}
    const match=/@@ -(\d+)(?:,(\d+))? \+(\d+)(?:,(\d+))? @@/.exec(header);
    if(!match)throw new Error(`잘못된 패치 hunk: ${relative} / ${header}`);
    const expected=Number(match[1])-1+offset;
    index++;
    const oldBlock:string[]=[];
    const newBlock:string[]=[];
    while(index<diffLines.length&&!diffLines[index]!.startsWith('@@')){
      const line=diffLines[index]!;
      if(line.startsWith('--- ')||line.startsWith('+++ ')){index++;continue;}
      if(line.startsWith(' ')){oldBlock.push(line.slice(1));newBlock.push(line.slice(1));}
      else if(line.startsWith('-'))oldBlock.push(line.slice(1));
      else if(line.startsWith('+'))newBlock.push(line.slice(1));
      index++;
    }
    const at=findBlock(lines,oldBlock,expected);
    if(at<0){
      const already=findBlock(lines,newBlock,expected);
      if(already>=0)continue;
      throw new Error(`패치 기준 불일치: ${relative} / hunk ${match[1]}. 004C UX Hotfix 적용 상태를 확인하세요.`);
    }
    lines.splice(at,oldBlock.length,...newBlock);
    offset+=newBlock.length-oldBlock.length;
  }
  fs.writeFileSync(target,lines.join('\n')+(hadFinalNewline?'\n':''),'utf8');
}

const requiredMarkers:[string,string][]=[
  ['client/src/GameScene.ts','playerOverlays'],
  ['client/src/network.ts','toSnapshot'],
  ['client/src/style.css','REFRACTOR_004C_CHAT_HOTFIX'],
  ['server/src/rooms/Drop8Room.ts',"this.onMessage('chat'"],
  ['server/src/rooms/schema.ts','reloadProgress'],
  ['shared/src/index.ts','BUSH_FIRE_REVEAL_SECONDS'],
  ['server/tests/room.test.ts','REFRACTOR_004B_SYNC_HOTFIX'],
  ['docs/PATCH_NOTES.md','Refactor 004C UX Hotfix'],
];
for(const [relative,marker] of requiredMarkers){
  const target=path.join(root,relative);
  if(!fs.existsSync(target)||!fs.readFileSync(target,'utf8').includes(marker)){
    throw new Error(`Refactor 005 기준 파일이 아닙니다: ${relative} / ${marker}`);
  }
}

const targets=[...Object.keys(patches),...Object.keys(newFiles)];
fs.mkdirSync(backupRoot,{recursive:true});
for(const relative of targets){
  const source=path.join(root,relative);
  if(!fs.existsSync(source))continue;
  const destination=path.join(backupRoot,relative);
  fs.mkdirSync(path.dirname(destination),{recursive:true});
  fs.copyFileSync(source,destination);
}

for(const [relative,diff] of Object.entries(patches))applyUnified(relative,diff);
for(const [relative,content] of Object.entries(newFiles)){
  const target=path.join(root,relative);
  if(fs.existsSync(target)){
    const current=fs.readFileSync(target,'utf8').replace(/\r\n/g,'\n');
    if(current!==content.replace(/\r\n/g,'\n'))throw new Error(`새 파일 충돌: ${relative}`);
    continue;
  }
  fs.mkdirSync(path.dirname(target),{recursive:true});
  fs.writeFileSync(target,content,'utf8');
}

